const input = $('Execute Workflow Trigger').first().json;
const action = String(input.action || '').toLowerCase();
const phone = input.phoneNumber;

const staticData = $getWorkflowStaticData('global');
if (!staticData.profiles) staticData.profiles = {};

if (action === 'cancel' || action === 'delete' || action === 'stop') {
  if (staticData.profiles[phone]) {
    delete staticData.profiles[phone];
    return [{ json: { replyMessage: "✅ Your commute reminder has been cancelled. Send 'save my commute' anytime to set it up again." } }];
  } else {
    return [{ json: { replyMessage: "You don't have a saved commute. Send 'save my commute' to set one up!" } }];
  }
}

// Save flow
const origin = input.commute_origin || 'Unknown';
const destination = input.commute_destination || 'Unknown';
const commuteTime = input.commute_time || '09:00'; // fallback

let days = input.commute_days;
if (typeof days === 'string') {
  try { days = JSON.parse(days); } catch(e) { days = days.split(',').map(s=>s.trim()); }
}
if (!Array.isArray(days) || days.length === 0) days = ["Monday","Tuesday","Wednesday","Thursday","Friday"]; // default

const parts = commuteTime.split(":").map(Number);
const h = parts[0] || 9;
const m = parts[1] || 0;
const reminderMins = h * 60 + m - 15;
let finalH = Math.floor(reminderMins / 60);
let finalM = reminderMins % 60;
if (reminderMins < 0) {
    finalH = Math.floor((24 * 60 + reminderMins) / 60);
    finalM = (24 * 60 + reminderMins) % 60;
}
const reminderTime = `${String(finalH).padStart(2,"0")}:${String(finalM).padStart(2,"0")}`;

staticData.profiles[phone] = {
  origin,
  destination,
  commute_time: commuteTime,
  reminder_time: reminderTime,
  days,
  saved_at: new Date().toISOString()
};

const replyMessage = `✅ *Commute saved!*\n\n🚇 ${origin} → ${destination}\n📅 ${days.join(", ")}\n⏰ Reminder at ${reminderTime} (15 min before your ${commuteTime} commute)\n\nI'll send you your trip plan automatically. You can update this anytime by saying "save my commute" again.`;

return [{ json: { replyMessage } }];
